def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    target_rows = rows + rows // 2
    def find_period(seq):
        n = len(seq)
        for p in range(1, n+1):
            valid = True
            for i in range(n):
                if seq[i] != seq[i % p]:
                    valid = False
                    break
            if valid:
                return p
        return n
    result = [[0] * cols for _ in range(target_rows)]
    for c in range(cols):
        col_vals = [grid[r][c] for r in range(rows)]
        period = find_period(col_vals)
        for r in range(target_rows):
            val = col_vals[r % period]
            result[r][c] = 2 if val == 1 else val
    return result

