def solve(grid):
    rows = len(grid)
    cols = len(grid[0])
    cells_8 = []
    cells_2 = []
    for r in range(rows):
        for c in range(cols):
            if grid[r][c] == 8:
                cells_8.append((r, c))
            elif grid[r][c] == 2:
                cells_2.append((r, c))
    r8_min = min(r for r,c in cells_8)
    r8_max = max(r for r,c in cells_8)
    c8_min = min(c for r,c in cells_8)
    c8_max = max(c for r,c in cells_8)
