    r2_max = max(r for r,c in cells_2)
    c2_min = min(c for r,c in cells_2)
    c2_max = max(c for r,c in cells_2)
    r8_center = (r8_min + r8_max) / 2
    c8_center = (c8_min + c8_max) / 2
    r2_center = (r2_min + r2_max) / 2
    c2_center = (c2_min + c2_max) / 2
    row_overlap = not (r2_max < r8_min or r2_min > r8_max)
    col_overlap = not (c2_max < c8_min or c2_min > c8_max)
    dr = 0
    dc = 0
    if col_overlap and not row_overlap:
        if r2_center < r8_center:
            dr = r8_min - r2_max - 1
        else:
            dr = r8_max - r2_min + 1
    elif row_overlap and not col_overlap:
        if c2_center < c8_center:
            dc = c8_min - c2_max - 1
        else:
            dc = c8_max - c2_min + 1
    else:
        row_dist = abs(r2_center - r8_center)
        col_dist = abs(c2_center - c8_center)
        if row_dist > col_dist:
            if r2_center < r8_center:
                dr = r8_min - r2_max - 1
            else:
                dr = r8_max - r2_min + 1
        else:
            if c2_center < c8_center:
                dc = c8_min - c2_max - 1
            else:
                dc = c8_max - c2_min + 1
    result = [[0]*cols for _ in range(rows)]
    for r, c in cells_8:
        result[r][c] = 8
    for r, c in cells_2:
        result[r + dr][c + dc] = 2
    return result

