        for c in range(cols):
            if grid[r][c] == 5:
                result[r][c] = 5
    for br in range(3):
        for bc in range(3):
            rs, cs = br * 4, bc * 4
            fill_val = key_grid[br][bc]
            for r in range(3):
                for c in range(3):
                    result[rs + r][cs + c] = fill_val
    return result
